  "logic.channelMonthlyInvestment": { pt: "Investimento mensal por canal", es: "Inversion mensual por canal", en: "Monthly investment by channel" },
  "logic.line": { pt: "Linha", es: "Linea", en: "Line" },
  "logic.channelRoasFormula": { pt: "ROAS por canal (receita / investimento)", es: "ROAS por canal (ingreso / inversion)", en: "ROAS by channel (revenue / investment)" },
